import { createClient } from "npm:@supabase/supabase-js@^2.98.0";
import { defineTool as defineTool2 } from "npm:@lovable.dev/mcp-js@0.20.0";
import { z } from "npm:zod@^4.4.3";
function supabaseForUser(ctx) {
  return createClient(process.env.SUPABASE_URL, process.env.SUPABASE_PUBLISHABLE_KEY, {
    global: { headers: { Authorization: `Bearer ${ctx.getToken()}` } },
    auth: { persistSession: false, autoRefreshToken: false }
  });
}
var list_students_default = defineTool2({
  name: "list_students",
  title: "List students",
  description: "List students visible to the signed-in user (filtered by Supabase RLS). Optional filter by grade (kelas) and rombel.",
  inputSchema: {
    kelas: z.number().int().min(1).max(6).optional().describe("Grade level (1-6)"),
    rombel: z.string().optional().describe("Class section, e.g. A, B, C, or D"),
    limit: z.number().int().min(1).max(200).optional().describe("Max rows to return (default 50)")
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: async ({ kelas, rombel, limit }, ctx) => {
    if (!ctx.isAuthenticated()) {
      return { content: [{ type: "text", text: "Not authenticated" }], isError: true };
    }
    const supabase = supabaseForUser(ctx);
    let query = supabase.from("students").select("id, nama, nis, nisn, kelas, rombel, level, status_bacaan, halaman_terakhir, perlu_perhatian").order("kelas").order("rombel").order("nama").limit(limit ?? 50);
    if (typeof kelas === "number") query = query.eq("kelas", kelas);
    if (rombel) query = query.eq("rombel", rombel);
    const { data, error } = await query;
    if (error) {
      return { content: [{ type: "text", text: error.message }], isError: true };
    }
    return {
      content: [{ type: "text", text: JSON.stringify(data) }],
      structuredContent: { students: data ?? [] }
    };
  }
});

